    ["Open Talents"] = "Offene Talente",
    ["Open reference windows, diagnostics, and addon utilities."] = "ГғВ–ffnen Sie Referenzfenster, Diagnose- und Add-on-Dienstprogramme.",
    ["Opens a compact searchable browser. Only eight reusable rows are created regardless of history size."] = "ГғВ–ffnet einen kompakten, durchsuchbaren Browser. UnabhГғВӨngig von der VerlaufsgrГғВ¶ГғВҹe werden nur acht wiederverwendbare Zeilen erstellt.",
    ["Opens selectable text. WoW 3.3.5a addons cannot write directly to the system clipboard."] = "ГғВ–ffnet auswГғВӨhlbaren Text. WoW 3.3.5a-Add-ons kГғВ¶nnen nicht direkt in die Systemzwischenablage schreiben.",
    ["Opens the complete build editor. Use the Character action below for direct access to saved gear, talents, glyphs, and affixes."] = "ГғВ–ffnet den vollstГғВӨndigen Build-Editor. Verwenden Sie die Charakteraktion unten, um direkten Zugriff auf gespeicherte AusrГғВјstung, Talente, Glyphen und Affixe zu erhalten.",
    ["Opens the decision logbook for the latest run and marks its summary as reviewed. Mixed-strategy runs remain clearly labeled."] = "ГғВ–ffnet das Entscheidungslogbuch fГғВјr den letzten Lauf und markiert seine Zusammenfassung als ГғВјberprГғВјft. LГғВӨufe mit gemischten Strategien bleiben klar gekennzeichnet.",
    ["Opens this build's saved talents, glyphs, gear, and affixes directly in the Character editor."] = "ГғВ–ffnet die gespeicherten Talente, Glyphen, AusrГғВјstungsgegenstГғВӨnde und Affixe dieses Builds direkt im Charaktereditor.",
